class Solution {
    private static final int MOD = 1_000_000_007;
    private int base;

    public int countNumbers(String l, String r, int b) {
        this.base = b;
        long upper = solve(r);
        long lower = solve(dec(l));
        return (int) ((upper - lower + MOD) % MOD);
    }

    private String dec(String s) {
        char[] cs = s.toCharArray();
        int n = cs.length, i = n - 1;
        while (i >= 0 && cs[i] == '0') {
            cs[i] = (char) ('0' + base - 1);
            i--;
        }
        if (i < 0) {
            char[] res = new char[n];
            Arrays.fill(res, '0');
            res[0] = '1';
            return new String(res);
        }
        cs[i]--;
        return new String(cs);
    }

    private long solve(String s) {
        char[] cs = s.toCharArray();
        int n = cs.length;
        long[][] dp = new long[n + 1][base];
        for (int d = 0; d < base; d++) dp[n][d] = 1;
        for (int i = n - 1; i >= 0; i--) {
            int limit = cs[i] - '0';
            for (int prev = 0; prev < base; prev++) {
                long res = 0;
                for (int d = prev; d < base; d++) {
                    if (d > limit) break;
                    if (d < limit) {
                        res += dp[i + 1][d];
                    } else {
                        res += dp[i + 1][prev];
                    }
                    res %= MOD;
                }
                dp[i][prev] = res;
            }
        }
        return dp[0][0];
    }
}
